48	pub struct ReplPanel {
49	    emulator: EmulatorCore,
50	    output: Vec<String>,
51	    input: String,
52	    running: bool,
53	    halted: bool,
54	    uart_rx_queue: VecDeque<u8>,
55	    /// Partial line buffer for UART output that hasn't ended with '\n' yet.
56	    partial_line: String,
57	    _tick_handle: Option<Timeout>,
58	    output_ref: NodeRef,
59	    panel_ref: NodeRef,
60	    needs_focus: bool,
61	    /// Track which reset_seq we last processed.
62	    last_reset_seq: u32,
