68	    last_rx: Option<u8>,
69	    /// Command history buffer.
70	    history: Vec<String>,
71	    /// Current position when browsing history (None = not browsing).
72	    history_index: Option<usize>,
73	    /// Saved in-progress input when browsing history.
74	    history_saved_input: String,
75	    /// True when the user has scrolled away from the bottom.
76	    user_scrolled_up: bool,
