79	impl ReplPanel {
80	    fn schedule_tick(ctx: &Context<Self>) -> Timeout {
81	        let link = ctx.link().clone();
82	        Timeout::new(TICK_MS, move || link.send_message(Msg::Tick))
83	    }
84	
85	    fn scroll_to_bottom(&self) {
86	        if self.user_scrolled_up {
87	            return;
88	        }
89	        if let Some(el) = self.output_ref.cast::<HtmlDivElement>() {
90	            el.set_scroll_top(el.scroll_height());
91	        }
92	    }
93	
94	    /// Check whether the output container is scrolled near the bottom.
95	    fn is_near_bottom(el: &HtmlElement) -> bool {
96	        let threshold = 20;
97	        el.scroll_top() + el.client_height() >= el.scroll_height() - threshold
98	    }
99	
100	    /// Load the pre-assembled APL binary and start the emulator.
101	    fn load_apl_binary(&mut self) {
102	        let binary = config::APL_BINARY;
103	        self.emulator.hard_reset();
104	        self.emulator.set_uart_tx_busy_cycles(0);
105	        self.emulator.load_program(0, binary);
106	        self.emulator.load_program_extent(binary.len() as u32);
107	        self.emulator.set_pc(0);
108	        self.emulator.resume();
109	        self.running = true;
110	        self.halted = false;
111	        self.output.clear();
112	        self.partial_line.clear();
113	        self.uart_rx_queue.clear();
114	        self.last_tx = None;
115	        self.last_rx = None;
116	    }
117	
118	    /// Feed bytes from the RX queue into the emulator UART while it's ready.
119	    fn feed_uart_bytes(&mut self) {
120	        while !self.uart_rx_queue.is_empty() {
121	            let status = self.emulator.read_byte(0xFF0101);
122	            if status & 0x01 != 0 {
123	                break; // RX buffer full, try again next tick
124	            }
125	            if let Some(byte) = self.uart_rx_queue.pop_front() {
126	                self.emulator.send_uart_byte(byte);
127	                self.last_rx = Some(byte);
128	            }
129	        }
130	    }
131	
132	    /// Collect UART output from the emulator and append to the output buffer.
133	    fn collect_uart(&mut self) {
134	        let uart = self.emulator.get_uart_output();
135	        if uart.is_empty() {
136	            return;
137	        }
138	        let uart = uart.to_string();
139	        self.emulator.clear_uart_output();
140	
141	        // Track last TX byte
142	        if let Some(b) = uart.bytes().last() {
143	            self.last_tx = Some(b);
144	        }
145	
146	        // Split on newlines, handling partial lines across ticks.
147	        for ch in uart.chars() {
148	            if ch == '\n' {
149	                self.output.push(std::mem::take(&mut self.partial_line));
150	            } else if ch != '\r' {
151	                self.partial_line.push(ch);
152	            }
153	        }
154	    }
155	
156	    /// Render a single output line, applying prettification to echoed input lines.
157	    fn render_line(line: &str, mode: DisplayMode) -> Html {
158	        // Lines starting with the 6-space prompt are echoed user input — prettify those.
159	        if let Some(content) = line.strip_prefix(PROMPT) {
160	            let segments = prettify_line(content, mode);
161	            html! {
162	                <div class="repl-line">
163	                    <span class="repl-prompt">{ PROMPT }</span>
