171	
172	    /// Render prettified segments with keyword highlighting.
173	    fn render_segments(segments: &[Segment]) -> Html {
174	        html! {
175	            { for segments.iter().map(|seg| match seg {
176	                Segment::Plain(text) => html! { <>{ text }</> },
177	                Segment::Keyword(text) => html! {
178	                    <span class="apl-keyword">{ text }</span>
179	                },
180	            })}
181	        }
182	    }
183	
184	    /// Queue text to be sent to the interpreter line-by-line.
185	    fn feed_program_text(&mut self, text: &str) {
186	        for line in text.lines() {
187	            let trimmed = line.trim();
188	            if trimmed.is_empty() {
189	                continue;
190	            }
191	            for b in trimmed.bytes() {
192	                self.uart_rx_queue.push_back(b);
193	            }
194	            self.uart_rx_queue.push_back(b'\n');
195	        }
196	    }
197	}
