199	impl Component for ReplPanel {
200	    type Message = Msg;
201	    type Properties = ReplPanelProps;
202	
203	    fn create(ctx: &Context<Self>) -> Self {
204	        ctx.link().send_message(Msg::Init);
205	        let mut emulator = EmulatorCore::new();
206	        emulator.set_uart_tx_busy_cycles(0);
207	        Self {
208	            emulator,
209	            output: vec!["APL / COR24 Environment".to_string(), String::new()],
210	            input: String::new(),
211	            running: false,
212	            halted: false,
213	            uart_rx_queue: VecDeque::new(),
214	            partial_line: String::new(),
215	            _tick_handle: None,
216	            output_ref: NodeRef::default(),
217	            panel_ref: NodeRef::default(),
218	            needs_focus: false,
219	            last_reset_seq: 0,
220	            last_feed_seq: 0,
221	            last_tx: None,
222	            last_rx: None,
223	            history: Vec::new(),
224	            history_index: None,
225	            history_saved_input: String::new(),
226	            user_scrolled_up: false,
227	        }
228	    }
229	
230	    fn changed(&mut self, ctx: &Context<Self>, _old_props: &Self::Properties) -> bool {
231	        let props = ctx.props();
232	
233	        // Handle reset command
234	        if props.reset_seq != self.last_reset_seq {
235	            self.last_reset_seq = props.reset_seq;
236	            self.load_apl_binary();
237	            self.needs_focus = true;
238	            // Always schedule a fresh tick — the old Timeout may have
239	            // already fired (e.g. after )OFF halt) but still be Some.
240	            self._tick_handle = Some(Self::schedule_tick(ctx));
241	        }
242	
243	        // Handle feed text command
244	        if props.feed_seq != self.last_feed_seq {
245	            self.last_feed_seq = props.feed_seq;
246	            self.feed_program_text(&props.feed_text);
247	            self.needs_focus = true;
248	        }
249	
250	        // S2 switch — use emulator API (active-low hardware)
251	        self.emulator.set_button_pressed(props.s2_on);
252	
253	        true
254	    }
255	
256	    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
257	        match msg {
258	            Msg::Init => {
259	                self.load_apl_binary();
260	                self._tick_handle = Some(Self::schedule_tick(ctx));
261	                true
262	            }
263	            Msg::Tick => {
264	                if !self.running || self.halted {
265	                    return false;
266	                }
267	
268	                self.feed_uart_bytes();
269	                let result = self.emulator.run_batch(BATCH_SIZE);
270	                self.collect_uart();
271	
272	                if matches!(result.reason, StopReason::Halted) {
273	                    self.halted = true;
274	                    self.running = false;
275	                    // Flush any remaining partial line
276	                    if !self.partial_line.is_empty() {
277	                        self.output.push(std::mem::take(&mut self.partial_line));
278	                    }
279	                    self.output.push(String::new());
280	                    self.output
281	                        .push("[Halted — press Reset to restart]".to_string());
282	                }
283	
284	                if self.running && !self.halted {
285	                    self._tick_handle = Some(Self::schedule_tick(ctx));
286	                }
287	
288	                // Report hardware state to parent (LED is active-low)
289	                let led_on = self.emulator.is_led_on();
290	                ctx.props()
291	                    .on_hw_state
292	                    .emit((led_on, self.last_tx, self.last_rx));
293	
294	                true
295	            }
296	            Msg::Scroll => {
297	                if let Some(el) = self.output_ref.cast::<HtmlElement>() {
298	                    let was = self.user_scrolled_up;
299	                    self.user_scrolled_up = !Self::is_near_bottom(&el);
300	                    // Only re-render if the flag changed (shows/hides the indicator)
301	                    was != self.user_scrolled_up
302	                } else {
303	                    false
304	                }
305	            }
306	            Msg::ScrollToBottom => {
307	                self.user_scrolled_up = false;
308	                if let Some(el) = self.output_ref.cast::<HtmlDivElement>() {
309	                    el.set_scroll_top(el.scroll_height());
310	                }
311	                true
312	            }
313	            Msg::KeyDown(e) => {
314	                // Let modifier combos (Cmd-C, Ctrl-V, etc.) pass through to browser
315	                if e.meta_key() || e.ctrl_key() || e.alt_key() {
316	                    return false;
317	                }
318	                // Ignore input when the emulator has halted (e.g. after )OFF)
319	                if self.halted {
320	                    return false;
321	                }
322	                let key = e.key();
323	                match key.as_str() {
324	                    "Enter" => {
325	                        e.prevent_default();
326	                        // Show the input line in output
327	                        let line = format!("{PROMPT}{}", self.input);
328	                        self.output.push(line);
329	                        // Queue input bytes for the emulator's UART
330	                        for b in self.input.bytes() {
331	                            self.uart_rx_queue.push_back(b);
332	                        }
333	                        self.uart_rx_queue.push_back(b'\n');
334	                        // Save non-empty input to history
335	                        if !self.input.is_empty() {
336	                            self.history.push(self.input.clone());
337	                        }
338	                        self.input.clear();
339	                        self.history_index = None;
340	                        true
341	                    }
342	                    "ArrowUp" => {
343	                        e.prevent_default();
344	                        if self.history.is_empty() {
345	                            return false;
346	                        }
347	                        let new_index = match self.history_index {
348	                            None => {
349	                                self.history_saved_input = self.input.clone();
350	                                self.history.len() - 1
351	                            }
352	                            Some(0) => return false,
353	                            Some(i) => i - 1,
354	                        };
355	                        self.history_index = Some(new_index);
356	                        self.input = self.history[new_index].clone();
357	                        true
358	                    }
359	                    "ArrowDown" => {
360	                        e.prevent_default();
361	                        match self.history_index {
362	                            None => return false,
363	                            Some(i) if i + 1 < self.history.len() => {
364	                                self.history_index = Some(i + 1);
365	                                self.input = self.history[i + 1].clone();
366	                            }
367	                            Some(_) => {
368	                                self.history_index = None;
369	                                self.input = std::mem::take(&mut self.history_saved_input);
370	                            }
371	                        }
372	                        true
373	                    }
374	                    "Backspace" => {
375	                        e.prevent_default();
376	                        self.input.pop();
377	                        true
378	                    }
379	                    _ => {
380	                        if key.len() == 1 {
381	                            e.prevent_default();
382	                            let ch = key.chars().next().unwrap();
383	                            if ch.is_ascii_graphic() || ch == ' ' {
384	                                self.input.push(ch);
385	                                return true;
386	                            }
387	                        }
388	                        false
389	                    }
390	                }
391	            }
392	        }
393	    }
394	
395	    fn rendered(&mut self, _ctx: &Context<Self>, first_render: bool) {
396	        self.scroll_to_bottom();
397	        if (first_render || self.needs_focus)
398	            && let Some(el) = self.panel_ref.cast::<HtmlDivElement>()
399	        {
400	            let _ = el.focus();
401	            self.needs_focus = false;
402	        }
403	    }
404	
405	    fn view(&self, ctx: &Context<Self>) -> Html {
406	        let onkeydown = ctx.link().callback(Msg::KeyDown);
407	        let onscroll = ctx.link().callback(|_: Event| Msg::Scroll);
408	        let on_scroll_btn = ctx.link().callback(|_: MouseEvent| Msg::ScrollToBottom);
409	        let mode = ctx.props().display_mode;
410	
411	        html! {
412	            <div class="repl-panel" tabindex="0" {onkeydown} ref={self.panel_ref.clone()}>
413	                <div class="repl-output" ref={self.output_ref.clone()} {onscroll}>
414	                    { for self.output.iter().map(|line| Self::render_line(line, mode)) }
415	                    // Show partial line if the emulator is mid-output
416	                    if !self.partial_line.is_empty() {
417	                        <div class="repl-line">{ &self.partial_line }</div>
418	                    }
419	                    <div class="repl-input-line">
420	                        <span class="repl-prompt">{ PROMPT }</span>
421	                        <span class="repl-input-text">
422	                            { Self::render_segments(&prettify_line(&self.input, mode)) }
423	                        </span>
424	                        <span class="repl-cursor">{"\u{2588}"}</span>
425	                    </div>
426	                </div>
427	                if self.user_scrolled_up {
428	                    <button class="scroll-to-bottom" onclick={on_scroll_btn}
429	                        title="Scroll to bottom">
430	                        {"↓ Bottom"}
431	                    </button>
432	                }
433	            </div>
434	        }
435	    }
436	}
