4	pub mod hardware;
5	pub mod prettify;
6	pub mod repl;
7	
8	use control_bar::ControlBar;
9	use hardware::HardwarePanel;
10	use prettify::DisplayMode;
11	use repl::ReplPanel;
12	use yew::prelude::*;
13	
14	pub enum Msg {
15	    Reset,
16	    LoadDemo(String),
17	    UploadProgram(String),
18	    ToggleS2,
19	    HwState(bool, Option<u8>, Option<u8>),
20	    SetDisplayMode(DisplayMode),
21	}
22	
23	pub struct App {
24	    reset_seq: u32,
25	    feed_seq: u32,
26	    feed_text: AttrValue,
27	    s2_on: bool,
28	    led_on: bool,
29	    last_tx: Option<u8>,
30	    last_rx: Option<u8>,
31	    display_mode: DisplayMode,
32	}
33	
34	impl Component for App {
35	    type Message = Msg;
36	    type Properties = ();
37	
38	    fn create(_ctx: &Context<Self>) -> Self {
39	        Self {
40	            reset_seq: 0,
41	            feed_seq: 0,
42	            feed_text: AttrValue::default(),
43	            s2_on: false,
44	            led_on: false,
45	            last_tx: None,
46	            last_rx: None,
47	            display_mode: DisplayMode::default(),
48	        }
49	    }
50	
51	    fn update(&mut self, _ctx: &Context<Self>, msg: Self::Message) -> bool {
52	        match msg {
53	            Msg::Reset => {
54	                self.reset_seq = self.reset_seq.wrapping_add(1);
55	                self.s2_on = false;
56	                self.led_on = false;
57	                self.last_tx = None;
58	                self.last_rx = None;
59	                true
60	            }
61	            Msg::LoadDemo(text) | Msg::UploadProgram(text) => {
62	                self.feed_text = AttrValue::from(text);
63	                self.feed_seq = self.feed_seq.wrapping_add(1);
64	                true
65	            }
66	            Msg::ToggleS2 => {
67	                self.s2_on = !self.s2_on;
68	                true
69	            }
70	            Msg::HwState(led, tx, rx) => {
71	                let changed = self.led_on != led || self.last_tx != tx || self.last_rx != rx;
72	                if changed {
73	                    self.led_on = led;
74	                    self.last_tx = tx;
75	                    self.last_rx = rx;
76	                }
77	                changed
78	            }
79	            Msg::SetDisplayMode(mode) => {
80	                if self.display_mode != mode {
81	                    self.display_mode = mode;
82	                    true
83	                } else {
84	                    false
85	                }
86	            }
87	        }
88	    }
89	
90	    fn view(&self, ctx: &Context<Self>) -> Html {
91	        let link = ctx.link();
